{
  "tags": [
    "Pagamentos"
  ],
  "summary": "Criar consentimento para a iniciação de pagamento.",
  "operationId": "paymentsPostConsents",
  "description": "Método de criação do consentimento para a iniciação de pagamento.",
  "parameters": [
    {
      "name": "Authorization",
      "in": "header",
      "description": "Cabeçalho HTTP padrão. Permite que as credenciais sejam fornecidas dependendo do tipo de recurso solicitado",
      "required": true,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 2048
      }
    },
    {
      "name": "x-fapi-auth-date",
      "in": "header",
      "description": "Data em que o usuário logou pela última vez com o receptor. Representada de acordo com a [RFC7231](https://tools.ietf.org/html/rfc7231).Exemplo: Sun, 10 Sep 2017 19:43:31 UTC",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "^(Mon|Tue|Wed|Thu|Fri|Sat|Sun), \\d{2} (Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec) \\d{4} \\d{2}:\\d{2}:\\d{2} (GMT|UTC)$",
        "minLength": 29,
        "maxLength": 29
      }
    },
    {
      "name": "x-fapi-customer-ip-address",
      "in": "header",
      "description": "O endereço IP do usuário se estiver atualmente logado com o receptor.",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 100
      }
    },
    {
      "name": "x-fapi-interaction-id",
      "in": "header",
      "description": "Um UUID [RFC4122](https://tools.ietf.org/html/rfc4122) usado como um ID de correlação entre request e response. Campo de geração e envio obrigatório pela iniciadora (client) e o seu valor deve ser “espelhado” pela detentora (server) no cabeçalho de resposta. Caso não seja enviado pela iniciadora, a detentora deve gerar um x-fapi-interaction-id e retorná-lo na resposta com o HTTP status code 400. Caso recebido um valor inválido, a detentora deve gerar um x-fapi-interaction-id e retorná-lo na resposta com o HTTP status code 400 ou 422 (com o código PARAMETRO_INVALIDO). A iniciadora deve acatar o valor gerado pelo detentor e recebido na resposta.",
      "required": true,
      "schema": {
        "type": "string",
        "pattern": "^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$",
        "minLength": 1,
        "maxLength": 36,
        "format": "uuid",
        "example": "d78fc4e5-37ca-4da3-adf2-9b082bf92280"
      }
    },
    {
      "name": "x-customer-user-agent",
      "in": "header",
      "description": "Indica o user-agent que o usuário utiliza.",
      "required": false,
      "schema": {
        "type": "string",
        "pattern": "[\\w\\W\\s]*",
        "minLength": 1,
        "maxLength": 100
      }
    },
    {
      "name": "x-idempotency-key",
      "in": "header",
      "description": "Cabeçalho HTTP personalizado. Identificador de solicitação exclusivo para suportar a idempotência.",
      "required": true,
      "schema": {
        "type": "string",
        "minLength": 1,
        "maxLength": 40,
        "pattern": "^(?!\\s)(.*)(\\S)$"
      }
    }
  ],
  "requestBody": {
    "content": {
      "application/jwt": {
        "schema": {
          "type": "object",
          "required": [
            "data"
          ],
          "properties": {
            "data": {
              "type": "object",
              "description": "Objeto contendo as informações de consentimento para a iniciação de pagamento.",
              "required": [
                "loggedUser",
                "creditor",
                "payment"
              ],
              "properties": {
                "loggedUser": {
                  "type": "object",
                  "description": "Usuário (pessoa natural) que encontra-se logado na instituição Iniciadora de Pagamento.",
                  "required": [
                    "document"
                  ],
                  "properties": {
                    "document": {
                      "type": "object",
                      "required": [
                        "identification",
                        "rel"
                      ],
                      "properties": {
                        "identification": {
                          "type": "string",
                          "maxLength": 11,
                          "description": "Número do documento de identificação oficial do usuário.",
                          "example": "11111111111",
                          "pattern": "^\\d{11}$"
                        },
                        "rel": {
                          "type": "string",
                          "maxLength": 3,
                          "description": "Tipo do documento de identificação oficial do usuário.",
                          "example": "CPF",
                          "pattern": "^[A-Z]{3}$"
                        }
                      }
                    }
                  }
                },
                "businessEntity": {
                  "type": "object",
                  "description": "Usuário (pessoa jurídica) que encontra-se logado na instituição Iniciadora de Pagamento. [Restrição] Preenchimento obrigatório se usuário logado na instituição Iniciadora de Pagamento for um CNPJ (pessoa jurídica).",
                  "required": [
                    "document"
                  ],
                  "properties": {
                    "document": {
                      "type": "object",
                      "required": [
                        "identification",
                        "rel"
                      ],
                      "properties": {
                        "identification": {
                          "type": "string",
                          "maxLength": 14,
                          "description": "Número do documento de identificação oficial do titular pessoa jurídica.",
                          "example": "11111111111111",
                          "pattern": "^[0-9A-Z]{12}[0-9]{2}$"
                        },
                        "rel": {
                          "type": "string",
                          "maxLength": 4,
                          "description": "Tipo do documento de identificação oficial do titular pessoa jurídica.",
                          "example": "CNPJ",
                          "pattern": "^[A-Z]{4}$"
                        }
                      }
                    }
                  }
                },
                "creditor": {
                  "type": "object",
                  "description": "Objeto contendo os dados do recebedor (creditor).",
                  "required": [
                    "personType",
                    "cpfCnpj",
                    "name"
                  ],
                  "properties": {
                    "personType": {
                      "type": "string",
                      "enum": [
                        "PESSOA_NATURAL",
                        "PESSOA_JURIDICA"
                      ],
                      "description": "Titular, pessoa natural ou juridica a quem se referem os dados de recebedor (creditor).\n"
                    },
                    "cpfCnpj": {
                      "type": "string",
                      "minLength": 11,
                      "maxLength": 14,
                      "pattern": "^([0-9]{11})$|^([0-9A-Z]{12}[0-9]{2})$",
                      "example": "58764789000137",
                      "description": "Identificação da pessoa envolvida na transação.  \nPreencher com o CPF ou CNPJ, de acordo com o valor escolhido no campo type.  \nO CPF será utilizado com 11 números e deverá ser informado sem pontos ou traços.  \nO CNPJ será utilizado com 14 números e deverá ser informado sem pontos ou traços.\n"
                    },
                    "name": {
                      "type": "string",
                      "pattern": "^[\\u0020-\\u007E\\u00A1-\\u00FF]+$",
                      "maxLength": 150,
                      "example": "Marco Antonio de Brito",
                      "description": "Em caso de pessoa natural deve ser informado o nome completo do titular da conta do recebedor.  \nEm caso de pessoa jurídica deve ser informada a razão social ou o nome fantasia da conta do recebedor.\n"
                    }
                  }
                },
                "payment": {
                  "type": "object",
                  "description": "Objeto contendo dados de pagamento para consentimento.",
                  "required": [
                    "type",
                    "currency",
                    "amount",
                    "details"
                  ],
                  "properties": {
                    "type": {
                      "type": "string",
                      "enum": [
                        "PIX"
                      ],
                      "example": "PIX",
                      "description": "Este campo define o tipo de pagamento que será iniciado após a autorização do consentimento.\n"
                    },
                    "purpose": {
                      "description": "Representa qual a finalidade da transação recebida.  \n- IMMEDIATE: Deve ser utilizado quando o pagamento gerado pelo consentimento for único e imediato e não for um Pix    Saque ou Pix Troco;  \n- SINGLE_SCHEDULED: Deve ser utilizado quando o pagamento gerado pelo consentimento for único e agendado;  \n- RECURRENT_SCHEDULED: Deve ser utilizado quando o pagamento gerado pelo consentimento não é único e é agendado;  \n- WITHDRAW: Deve ser utilizado quando o pagamento for único, imediato e representar uma operação de saque;  \n- CHANGE: Deve ser utilizado quando o pagamento for único, imediato e representar uma operação de troco.\n\n[Restrições]   \n- Campo de envio obrigatório quando o valor do campo /data/payment/type for igual a PIX, e;  \n- Se preenchido o objetivo /data/payment/scheduled/single, apenas o valor SINGLE_SCHEDULED é permitidos, ou;  \n- Se preenchido um dos objetos /data/payment/scheduled/daily, /data/payment/scheduled/weekly, /data/payment/scheduled/monthly ou /data/payment/scheduled/custom, apenas o valor RECURRENT_SCHEDULED é permitido.\n",
                      "type": "string",
                      "enum": [
                        "IMMEDIATE",
                        "SINGLE_SCHEDULED",
                        "RECURRENT_SCHEDULED",
                        "WITHDRAW",
                        "CHANGE"
                      ]
                    },
                    "schedule": {
                      "description": "[Restrição] Mutuamente excludente com o campo date. \nEste campo é obrigatório no caso de agendamento. \nNeste caso, o campo date não deverá ser informado. \nO prazo máximo para o consentimento deverá ser de dois anos, contando a partir da data de criação do consentimento retornada na criação do mesmo (campo /data/creationDateTime). \nAgendamento de pagamento único deve utilizar exclusivamente o objeto \"single\".\n",
                      "oneOf": [
                        {
                          "type": "object",
                          "required": [
                            "single"
                          ],
                          "properties": {
                            "single": {
                              "type": "object",
                              "description": "Define a política de agendamento único.",
                              "required": [
                                "date"
                              ],
                              "properties": {
                                "date": {
                                  "type": "string",
                                  "format": "date",
                                  "maxLength": 10,
                                  "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                                  "example": "2023-08-23",
                                  "description": "Define a data alvo da liquidação do pagamento. O fuso horário de Brasília deve ser utilizado para criação e racionalização sobre os dados deste campo.  \n[Restrição] Esse campo deverá sempre ser no mínimo D+1 corrido, ou seja, a data imediatamente posterior em relação à data de criação do consentimento. O prazo máximo admitido para agendamento é de dois anos, contados a partir da data de criação do consentimento, limitando-se ao dia e mês correspondentes no segundo ano subsequente (Ex.: consentimento criado em 10/07/2026 permite agendamento até 10/07/2028).\n"
                                }
                              }
                            }
                          }
                        },
                        {
                          "type": "object",
                          "required": [
                            "daily"
                          ],
                          "properties": {
                            "daily": {
                              "type": "object",
                              "required": [
                                "startDate",
                                "quantity"
                              ],
                              "properties": {
                                "startDate": {
                                  "description": "Define o início da vigência da recorrência.",
                                  "type": "string",
                                  "format": "date",
                                  "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                                  "maxLength": 10,
                                  "example": "2023-08-23"
                                },
                                "quantity": {
                                  "description": "Define a quantidade de pagamentos que serão enviados para liquidação.",
                                  "type": "integer",
                                  "format": "int32",
                                  "minimum": 2,
                                  "maximum": 60,
                                  "example": 3
                                }
                              }
                            }
                          }
                        },
                        {
                          "type": "object",
                          "required": [
                            "weekly"
                          ],
                          "properties": {
                            "weekly": {
                              "type": "object",
                              "required": [
                                "dayOfWeek",
                                "startDate",
                                "quantity"
                              ],
                              "properties": {
                                "dayOfWeek": {
                                  "description": "Define o dia da semana planejado para a ocorrência das liquidações.",
                                  "type": "string",
                                  "enum": [
                                    "SEGUNDA_FEIRA",
                                    "TERCA_FEIRA",
                                    "QUARTA_FEIRA",
                                    "QUINTA_FEIRA",
                                    "SEXTA_FEIRA",
                                    "SABADO",
                                    "DOMINGO"
                                  ],
                                  "example": "QUINTA_FEIRA"
                                },
                                "startDate": {
                                  "description": "Define o início da vigência da recorrência.",
                                  "type": "string",
                                  "format": "date",
                                  "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                                  "maxLength": 10,
                                  "example": "2023-08-23"
                                },
                                "quantity": {
                                  "description": "Define a quantidade de pagamentos que serão enviados para liquidação.",
                                  "type": "integer",
                                  "format": "int32",
                                  "minimum": 2,
                                  "maximum": 60,
                                  "example": 10
                                }
                              }
                            }
                          }
                        },
                        {
                          "type": "object",
                          "required": [
                            "monthly"
                          ],
                          "properties": {
                            "monthly": {
                              "type": "object",
                              "required": [
                                "dayOfMonth",
                                "startDate",
                                "quantity"
                              ],
                              "properties": {
                                "dayOfMonth": {
                                  "description": "Define o dia do mês planejado para a ocorrência das liquidações.",
                                  "type": "integer",
                                  "minimum": 1,
                                  "maximum": 31,
                                  "example": 10
                                },
                                "startDate": {
                                  "description": "Define o início da vigência da recorrência.",
                                  "type": "string",
                                  "format": "date",
                                  "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                                  "maxLength": 10,
                                  "example": "2023-08-23"
                                },
                                "quantity": {
                                  "description": "Define a quantidade de pagamentos que serão enviados para liquidação.",
                                  "type": "integer",
                                  "format": "int32",
                                  "minimum": 2,
                                  "maximum": 24,
                                  "example": 24
                                }
                              }
                            }
                          }
                        },
                        {
                          "type": "object",
                          "required": [
                            "custom"
                          ],
                          "properties": {
                            "custom": {
                              "type": "object",
                              "description": "[Restrição] As datas enviadas na lista de datas (array “dates”) não podem ser repetidas. \nCaso datas repetidas sejam enviadas, o detentor deve rejeitar a criação do consentimento, informando o erro PARAMETRO_INVALIDO.\n",
                              "required": [
                                "dates"
                              ],
                              "properties": {
                                "dates": {
                                  "description": "Define os dias em que estão planejadas as ocorrências das liquidações.",
                                  "type": "array",
                                  "maxItems": 60,
                                  "minItems": 2,
                                  "example": [
                                    "2023-08-23",
                                    "2023-09-26"
                                  ],
                                  "items": {
                                    "type": "string",
                                    "format": "date",
                                    "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                                    "maxLength": 10,
                                    "example": "2023-08-23"
                                  }
                                }
                              }
                            }
                          }
                        }
                      ],
                      "type": "object",
                      "required": [
                        "additionalInformation"
                      ],
                      "properties": {
                        "additionalInformation": {
                          "type": "string",
                          "description": "Texto livre para o Iniciador descrever de forma compreensível pelo usuário aprovador/pagador as características do agendamento solicitado.  \nO texto pode ser utilizado pelo detentor para exibição do resumo da transação durante aprovação do usuário aprovador/pagador.\n",
                          "pattern": "[\\w\\W\\s]*",
                          "maxLength": 255,
                          "example": "Todas quintas e domingos por 6 meses"
                        }
                      }
                    },
                    "date": {
                      "type": "string",
                      "format": "date",
                      "maxLength": 10,
                      "pattern": "^(\\d{4})-(1[0-2]|0?[1-9])-(3[01]|[12][0-9]|0?[1-9])$",
                      "example": "2021-01-01",
                      "description": "[Restrição] Mutuamente excludente com o objeto schedule. \n\nEste campo é obrigatório no caso de pagamento único. \n\nNeste caso, o objeto schedule não deve ser informado.\n"
                    },
                    "currency": {
                      "type": "string",
                      "maxLength": 3,
                      "pattern": "^([A-Z]{3})$",
                      "example": "BRL",
                      "description": "Código da moeda nacional segundo modelo ISO-4217, ou seja, 'BRL'.\nTodos os valores monetários informados estão representados com a moeda vigente do Brasil.\n"
                    },
                    "amount": {
                      "type": "string",
                      "minLength": 4,
                      "maxLength": 19,
                      "pattern": "^((\\d{1,16}\\.\\d{2}))$",
                      "example": "100000.12",
                      "description": "Valor da transação com 2 casas decimais. Para pagamento de QRCodes, a composição do valor segue as regras abaixo, de acordo com o tipo de QRCode e o produto associado a ele:  \n ▪ QR Code Estático: Se o QR Code contém valor, o campo amount deve ser preenchido com esse valor. Se o valor não estiver presente, o valor deve ser preenchido pelo usuário pagador, em ambiente da ITP, antes da criação do consentimento.  \n ▪ QR Code Dinâmico de Cobrança Imediata (COB): O campo amount deve ser preenchido com o valor da cobrança (valor.original). Quando valor.modalidadeAlteracao for igual a 1, o valor pode ser alterado pelo usuário pagador, em ambiente da ITP, antes da criação do consentimento.  \n ▪ QR Code Dinâmico de Cobrança com Vencimento (COBV): O campo amount deve ser preenchido com o valor final da cobrança, correspondente à composição: valor original, deduzidos eventuais abatimentos e descontos, acrescidos de eventuais juros e multa. O campo modalidadeAlteracao não se aplica a COBV; o valor não pode ser alterado pelo usuário pagador.  \n ▪ QR Code Dinâmico de Pix Saque: O campo amount deve ser preenchido com o valor do saque (valor.retirada.saque.valor). Quando valor.retirada.saque.modalidadeAlteracao for igual a 1, o valor do saque pode ser alterado pelo usuário pagador, em ambiente da ITP, antes da criação do consentimento e respeitados os limites definidos pelo facilitador de serviço de saque.  \n ▪ QR Code Dinâmico de Pix Troco: O campo amount deve ser preenchido com o valor total da transação, correspondente à soma do valor da compra (valor.original) com o valor do troco (valor.retirada.troco.valor). O valor da compra (valor.original) não pode ser alterado. Quando valor.retirada.troco.modalidadeAlteracao for igual a 1, apenas o valor do troco pode ser alterado pelo usuário pagador, em ambiente da ITP, antes da criação do consentimento e respeitados os limites definidos pelo facilitador de serviço de saque.  \n ▪ Para todos os cenários em que o valor não pode ser alterado, o campo amount deve ser preenchido com o valor estabelecido no QR Code. Caso o campo amount seja preenchido com valor divergente do esperado, deve ser retornado o erro HTTP Status 422 com código VALOR_INVALIDO.  \n"
                    },
                    "ibgeTownCode": {
                      "type": "string",
                      "minLength": 7,
                      "maxLength": 7,
                      "pattern": "^\\d{7}$",
                      "example": "5300108",
                      "description": "O campo ibgetowncode, no arranjo PIX, tem o mesmo comportamento que o campo codMun descrito no manual do PIX.  \nCaso a informação referente ao município não seja enviada; o PSP do recebedor assumirá que não existem feriados estaduais e municipais no período em questão;  \nNo caso de QRCode Dinâmico com vencimento, deve prevalecer o código do município do usuário pagador informado pelo prestador do serviço de iniciação.   \n[Restrição] Para QRCode Dinâmico com vencimento é obrigatório o envio desse parâmetro pelo ITP para que o Detentor possa utiliza-lo em sua consulta. É obrigatório que o Detentor utilize o valor informado pelo ITP em sua consulta ao QRCode no PSP Recebedor\n"
                    },
                    "details": {
                      "type": "object",
                      "description": "Objeto contendo os detalhes do pagamento.\n",
                      "required": [
                        "localInstrument",
                        "creditorAccount"
                      ],
                      "properties": {
                        "payloadJWS": {
                          "description": "Representa o payloadJWS obtido pela ITP na leitura do QR dinâmico. Devem ser enviados todos os fragmentos capturados do JWT que representa o QR gerado pelo PSP do Recebedor, permitindo ao detentor de contas validar os dados das cobranças repassadas pelo ITP.   \n[Restrição] Campo de envio obrigatório quando o valor presente em ```/data/payment/details/localInstrument``` for igual a APDN ou QRDN.\n",
                          "type": "string",
                          "maxLength": 16384,
                          "pattern": "^[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]+$",
                          "example": "eyJhbGciOiJSUzI1NiIsInR5cCI6IkpXUyIsImtpZCI6IjIwMTEtMDQtMjkiLCJqa3UiOiJodHRwczovL3Rvb2xzLmlldGYub3JnL2h0bWwvcmZjNzUxNyIsIng1dCI6IkFwcGVuZGl4QUV4YW1wbGVBMUpXS1NSc2FLZXkifQ..qI7NUrYkwcgXmyoyOjt2YLQyhxH-lPdr3xQ7RId9TDXZ-MlWmPJkUScjuo1Nz_EvlSotbWDGOxErBXHeTLHOQM-9T7lBmG5iw6uEX7L5U72XiganIm80EZCFD1vBPq9j89i4cP2U2Yv21TTt8JLhjA57KHLOSlj-KB5UAKCH-MX3AORFcrXFrYL2rrSQDe-lFNtdyPRwLQHIrhkQ6RR2FPhynzUG0401LScS9mWLLYbYzhzwtP5lk07Ryf4MZq86ihmOLFZXkIiW7pbSd8QfD5Dvj28XebLQi_bam9wInqKB--57_N741BskCN_TXf0EHbQ1qjNTgiT8Y1GIrA4pFA"
                        },
                        "localInstrument": {
                          "type": "string",
                          "enum": [
                            "MANU",
                            "DICT",
                            "QRDN",
                            "QRES",
                            "INIC",
                            "APES",
                            "APDN"
                          ],
                          "example": "DICT",
                          "description": "Especifica a forma de iniciação do pagamento:\n- MANU - Inserção manual de dados da conta transacional\n- DICT - Inserção manual de chave Pix\n- APDN - Leitura de QR code dinâmico via NFC  \n- QRDN - Leitura QR code dinâmico (exceto NFC)\n- APES - Leitura de QR code estático via NFC\n- QRES - Leitura de QR code estático (exceto NFC) \n- INIC - Indica que o recebedor (creditor) contratou o Iniciador de Pagamentos especificamente para realizar iniciações de pagamento em que o beneficiário é previamente conhecido.\n\n[Restrição] Se /data/payment/schedule enviado com valor diferente de single durante a criação do consentimento, apenas os métodos MANU, DICT ou QRES são permitidos.\n"
                        },
                        "qrCode": {
                          "type": "string",
                          "maxLength": 512,
                          "pattern": "[\\w\\W\\s]*",
